  describe('Business Rules', () => {
    describe('Service Demand as Hard Constraint', () => {
      test('should mark as violation when available < required', () => {
        const available = 85;
        const required = 102;
        const isViolation = available < required;

        expect(isViolation).toBe(true);
      });

      test('should mark as OK when available >= required', () => {
        const available = 110;
        const required = 102;
        const isViolation = available < required;

        expect(isViolation).toBe(false);
      });
    });

    describe('Default Demand Calculation', () => {
      test('should calculate 85% of fleet as default', () => {
        const fleetSize = 128;
        const expectedDefault = Math.ceil(fleetSize * 0.85);

        expect(expectedDefault).toBe(109);
      });

      test('should round up for safety', () => {
        const fleetSize = 100;
        const defaultPct = 0.85;
        const calculated = Math.ceil(fleetSize * defaultPct);

        expect(calculated).toBe(85); // 85% of 100 = 85
      });

      test('should handle small fleets', () => {
        const fleetSize = 10;
        const defaultPct = 0.85;
        const calculated = Math.ceil(fleetSize * defaultPct);

        expect(calculated).toBe(9); // ceil(8.5) = 9
      });
    });

    describe('Standby Buffer', () => {
      test('should default to 2 trains standby', () => {
        const defaultBuffer = 2;
        const minRequired = 100;
        const totalRequired = minRequired + defaultBuffer;

        expect(totalRequired).toBe(102);
      });

      test('should add standby buffer to total required', () => {
        const minRequired = 100;
        const standbyBuffer = 5;
        const totalRequired = minRequired + standbyBuffer;

        expect(totalRequired).toBe(105);
      });
    });

    describe('Peak Period Requirements', () => {
      test('should allow higher requirements during peak AM', () => {
        const baseRequired = 100;
        const peakAmRequired = 110;

        expect(peakAmRequired).toBeGreaterThan(baseRequired);
      });

      test('should allow lower requirements during evening', () => {
        const baseRequired = 100;
        const eveningRequired = 80;

        expect(eveningRequired).toBeLessThan(baseRequired);
      });

      test('should use base requirement when period not specified', () => {
        const baseRequired = 100;
        const periodRequired: number | null = null;
        const effective = periodRequired ?? baseRequired;

        expect(effective).toBe(baseRequired);
      });
    });

    describe('Effective Date Versioning', () => {
      test('should use most recent effective date', () => {
        const configs = [
          { effectiveDate: '2025-01-01', minTrainsRequired: 90 },
          { effectiveDate: '2025-06-01', minTrainsRequired: 95 },
          { effectiveDate: '2026-01-01', minTrainsRequired: 100 },
        ];

        // Sort by effective date descending
        const sorted = configs.sort((a, b) =>
          b.effectiveDate.localeCompare(a.effectiveDate)
        );

        // Most recent is first
        expect(sorted[0].minTrainsRequired).toBe(100);
      });

      test('should not use future effective dates', () => {
        const targetDate = '2026-01-15';
        const configs = [
          { effectiveDate: '2026-01-01', minTrainsRequired: 100 },
          { effectiveDate: '2026-02-01', minTrainsRequired: 105 }, // Future
        ];

        // Filter to configs effective on or before target date
        const applicable = configs.filter(
          (c) => c.effectiveDate <= targetDate
        );

        expect(applicable.length).toBe(1);
        expect(applicable[0].minTrainsRequired).toBe(100);
      });
    });

    describe('Violation Severity', () => {
      test('should mark HARD severity for service demand violations', () => {
        const violation: DemandViolation = {
          date: '2026-01-19',
          dayType: 'WEEKDAY',
          trainId: 'train-123',
          trainNumber: '1001',
          pmCode: 'C2',
          required: 102,
          available: 100,
          shortfall: 2,
          severity: 'HARD',
          message: 'Violation message',
        };

        // Service demand is always a HARD constraint
        expect(violation.severity).toBe('HARD');
      });
    });

    describe('Availability Calculation', () => {
      test('should subtract in-maintenance from fit trains', () => {
        const fitTrains = 115;
        const inMaintenance = 5;
        const available = fitTrains - inMaintenance;

        expect(available).toBe(110);
      });

      test('should subtract additional unavailable (proposed PM)', () => {
        const fitTrains = 115;
        const inMaintenance = 5;
        const additionalUnavailable = 3;
        const available = fitTrains - inMaintenance - additionalUnavailable;

        expect(available).toBe(107);
      });

      test('should not count restricted or grounded trains as available', () => {
        const totalTrains = 128;
        const fitTrains = 115;
        const restrictedTrains = 8;
        const groundedTrains = 5;

        expect(fitTrains + restrictedTrains + groundedTrains).toBe(totalTrains);
        // Only FIT trains are available for service
        expect(fitTrains).toBeLessThan(totalTrains);
      });
    });

    describe('Holiday Handling', () => {
      test('should override day-of-week with holiday', () => {
        const service = new ServiceDemandService();

        // 2026-01-26 is a Monday (would be WEEKDAY)
        // But if it's in the holiday list, should be HOLIDAY
        const holidays = ['2026-01-26'];

        expect(service.getDayType('2026-01-26', holidays)).toBe('HOLIDAY');
        expect(service.getDayType('2026-01-26')).toBe('WEEKDAY'); // Without holiday list
      });
    });

    describe('Warning Threshold', () => {
      test('should warn when surplus is less than 10% of total', () => {
        const totalTrains = 128;
        const warningThresholdPct = 0.10;
        const warningThreshold = totalTrains * warningThresholdPct;

        expect(warningThreshold).toBe(12.8);

        // If surplus < 12.8, should warn
        const surplus = 10;
        const shouldWarn = surplus < warningThreshold;

        expect(shouldWarn).toBe(true);
      });
    });
  });

  describe('Optimizer Integration', () => {
    test('should provide OptimizerConstraints-compatible output', () => {
      // The service demand validation should be usable by the optimizer
      const validation: AvailabilityValidation = {
        isValid: false,
        fleetId: 'fleet-123',
        date: '2026-01-19',
        dayType: 'WEEKDAY',
        totalTrains: 128,
        fitTrains: 100,
        unavailableTrains: 28,
        inMaintenanceTrains: 5,
        additionalUnavailable: 0,
        availableTrains: 95,
        required: 102,
        surplus: -7,
        severity: 'VIOLATION',
        message: 'HARD CONSTRAINT VIOLATED',
      };

      // Optimizer should reject any solution where isValid = false
      expect(validation.isValid).toBe(false);
      expect(validation.surplus).toBeLessThan(0);
    });

    test('should support batch violation checking for optimizer', () => {
      // Optimizer may check multiple PMs at once
      const proposedPMs: ProposedPM[] = [
        { trainId: 'train-1', targetDate: '2026-01-19' },
        { trainId: 'train-2', targetDate: '2026-01-19' },
        { trainId: 'train-3', targetDate: '2026-01-20' },
      ];

      // Group by date
      const byDate = new Map<string, ProposedPM[]>();
      for (const pm of proposedPMs) {
        const existing = byDate.get(pm.targetDate) ?? [];
        existing.push(pm);
        byDate.set(pm.targetDate, existing);
      }

      expect(byDate.get('2026-01-19')?.length).toBe(2);
      expect(byDate.get('2026-01-20')?.length).toBe(1);
    });
  });

  describe('12-Year Contract Support', () => {
    test('should support long date ranges', () => {
      // MMS is a 12-year contract; dates should span 2026-2038
      const startDate = '2026-01-01';
      const endDate = '2038-12-31';

      // Validate dates are parseable
      const start = new Date(startDate);
      const end = new Date(endDate);

      expect(end.getFullYear() - start.getFullYear()).toBe(12);
    });

    test('should handle leap years in date calculations', () => {
      const service = new ServiceDemandService();

      // 2028 is a leap year; Feb 29 exists
      expect(service.getDayType('2028-02-29')).toBeDefined();

      // Should still calculate day type correctly
      // Feb 29, 2028 is a Tuesday
      expect(service.getDayType('2028-02-29')).toBe('WEEKDAY');
    });
  });

  describe('Audit Trail Support', () => {
    test('should include source tracking in demand config', () => {
      const config: DemandConfig = {
        fleetId: 'fleet-123',
        fleetCode: 'KS',
        date: '2026-01-19',
        dayType: 'WEEKDAY',
        minTrainsRequired: 100,
        standbyBuffer: 2,
        totalRequired: 102,
        peakAmRequirement: null,
        middayRequirement: null,
        peakPmRequirement: null,
        eveningRequirement: null,
        source: 'CONFIG',
        sourceRecord: null,
      };

      // Source indicates whether from config or default
      expect(['CONFIG', 'DEFAULT']).toContain(config.source);
    });

    test('should track creation metadata in requests', () => {
      const request: CreateDemandRequest = {
        fleetId: 'fleet-123',
        effectiveDate: '2026-01-01',
        dayType: 'WEEKDAY',
        minTrainsRequired: 100,
        source: 'OPERATIONS',
        notes: 'Q1 2026 service pattern adjustment',
        createdBy: 'user-456',
      };

      expect(request.createdBy).toBeDefined();
      expect(request.notes).toBeDefined();
      expect(request.source).toBe('OPERATIONS');
    });
  });
});

