/**
 * MMS Route Utilization Service Unit Tests
 *
 * Tests for the Route Utilization Service covering:
 * - Profile retrieval with effective date lookup
 * - Daily rate calculation with fallback hierarchy
 * - Mileage projection over time horizons
 * - Seasonal multiplier application
 * - Confidence scoring based on data source
 * - Fleet average calculation from mileage readings
 * - CRUD operations for utilization profiles
 *
 * This is a CRITICAL service for MMS v2.1:
 * - Accurate mileage projections are essential for PM scheduling
 * - Fleet-wide averages can cause 60,000+ km projection errors over 12 years
 * - Route-specific profiles provide the highest accuracy
 *
 * @see src/services/route-utilization.ts
 * @see specs/004-domain-services.md Section 4.2.7
 */

import { describe, test, expect } from 'bun:test';
import {
  RouteUtilizationService,
  type UtilizationDayType,
  type ConfidenceLevel,
  type RateSource,
  type DailyRateResult,
  type MileageProjection,
  type RouteProfileWithMeta,
  type CreateProfileRequest,
  type UpdateProfileRequest,
  type ProfileListFilters,
  type FleetAverageResult,
} from './route-utilization';

// Note: These tests document the expected behavior and serve as a specification.
// Integration tests with actual database should be in a separate test suite.

describe('RouteUtilizationService', () => {
  describe('Initialization', () => {
    test('should create a RouteUtilizationService instance', () => {
      const service = new RouteUtilizationService();
      expect(service).toBeDefined();
      expect(service).toBeInstanceOf(RouteUtilizationService);
    });
  });

  describe('Day Type Calculation', () => {
    test('should identify weekdays correctly', () => {
      const service = new RouteUtilizationService();

      // Monday (2026-01-19 is a Monday)
      expect(service.getDayType('2026-01-19')).toBe('WEEKDAY');
      // Tuesday
      expect(service.getDayType('2026-01-20')).toBe('WEEKDAY');
      // Wednesday
      expect(service.getDayType('2026-01-21')).toBe('WEEKDAY');
      // Thursday
      expect(service.getDayType('2026-01-22')).toBe('WEEKDAY');
      // Friday
      expect(service.getDayType('2026-01-23')).toBe('WEEKDAY');
    });

    test('should identify Saturday correctly', () => {
      const service = new RouteUtilizationService();
      // 2026-01-24 is Saturday
      expect(service.getDayType('2026-01-24')).toBe('SATURDAY');
    });

    test('should identify Sunday correctly', () => {
      const service = new RouteUtilizationService();
      // 2026-01-25 is Sunday
      expect(service.getDayType('2026-01-25')).toBe('SUNDAY');
    });

    test('should identify holidays from provided list', () => {
      const service = new RouteUtilizationService();
      const holidays = ['2026-01-01', '2026-01-26', '2026-12-25'];

      // Jan 1 is a holiday (would be Thursday)
      expect(service.getDayType('2026-01-01', holidays)).toBe('HOLIDAY');

      // Jan 26 is a holiday (would be Monday)
      expect(service.getDayType('2026-01-26', holidays)).toBe('HOLIDAY');

      // Dec 25 is a holiday
      expect(service.getDayType('2026-12-25', holidays)).toBe('HOLIDAY');
    });

    test('should return weekday for non-holiday weekday dates', () => {
      const service = new RouteUtilizationService();
      const holidays = ['2026-01-01'];

      // Jan 2 is not a holiday
      expect(service.getDayType('2026-01-02', holidays)).toBe('WEEKDAY');
    });
  });

  describe('Peak Season Detection', () => {
    test('should identify peak months correctly (CNY, school holidays)', () => {
      const service = new RouteUtilizationService();

      // Peak months: Jan(0), Feb(1), Jun(5), Nov(10), Dec(11)
      expect(service.isPeakSeason('2026-01-15')).toBe(true); // January
      expect(service.isPeakSeason('2026-02-15')).toBe(true); // February (CNY)
      expect(service.isPeakSeason('2026-06-15')).toBe(true); // June (school)
      expect(service.isPeakSeason('2026-11-15')).toBe(true); // November
      expect(service.isPeakSeason('2026-12-15')).toBe(true); // December
    });

    test('should identify off-peak months correctly', () => {
      const service = new RouteUtilizationService();

      // Off-peak months: Mar(2), Apr(3), May(4), Jul(6), Aug(7), Sep(8), Oct(9)
      expect(service.isPeakSeason('2026-03-15')).toBe(false); // March
      expect(service.isPeakSeason('2026-04-15')).toBe(false); // April
      expect(service.isPeakSeason('2026-05-15')).toBe(false); // May
      expect(service.isPeakSeason('2026-07-15')).toBe(false); // July
      expect(service.isPeakSeason('2026-08-15')).toBe(false); // August
      expect(service.isPeakSeason('2026-09-15')).toBe(false); // September
      expect(service.isPeakSeason('2026-10-15')).toBe(false); // October
    });
  });

  describe('Type Definitions', () => {
    describe('UtilizationDayType', () => {
      test('should support all day types', () => {
        const dayTypes: UtilizationDayType[] = ['WEEKDAY', 'SATURDAY', 'SUNDAY', 'HOLIDAY'];
        expect(dayTypes.length).toBe(4);
      });
    });

    describe('ConfidenceLevel', () => {
      test('should support all confidence levels', () => {
        const levels: ConfidenceLevel[] = ['HIGH', 'MEDIUM', 'LOW', 'ESTIMATED'];
        expect(levels.length).toBe(4);
      });

      test('confidence hierarchy should be HIGH > MEDIUM > LOW > ESTIMATED', () => {
        // Document the confidence hierarchy for reference
        const hierarchy: Record<ConfidenceLevel, number> = {
          HIGH: 4,
          MEDIUM: 3,
          LOW: 2,
          ESTIMATED: 1,
        };

        expect(hierarchy.HIGH).toBeGreaterThan(hierarchy.MEDIUM);
        expect(hierarchy.MEDIUM).toBeGreaterThan(hierarchy.LOW);
        expect(hierarchy.LOW).toBeGreaterThan(hierarchy.ESTIMATED);
      });
    });

    describe('RateSource', () => {
      test('should support route-specific source format', () => {
        const routeSource: RateSource = 'route:abc-123-uuid';
        expect(routeSource.startsWith('route:')).toBe(true);
      });

      test('should support fleet_average source', () => {
        const fleetSource: RateSource = 'fleet_average';
        expect(fleetSource).toBe('fleet_average');
      });

      test('should support system_default source', () => {
        const defaultSource: RateSource = 'system_default';
        expect(defaultSource).toBe('system_default');
      });
    });

    describe('DailyRateResult', () => {
      test('should include required fields for route-based rate', () => {
        const result: DailyRateResult = {
          dailyKm: 320,
          source: 'route:north-south-line',
          confidence: 'HIGH',
          details: {
            routeId: 'north-south-line',
            routeCode: 'NSL',
            dayType: 'WEEKDAY',
            seasonalMultiplier: 1.0,
            profileEffectiveDate: '2026-01-01',
          },
        };

        expect(result.dailyKm).toBe(320);
        expect(result.confidence).toBe('HIGH');
        expect(result.details?.routeId).toBeDefined();
      });

      test('should include required fields for fleet-average rate', () => {
        const result: DailyRateResult = {
          dailyKm: 275,
          source: 'fleet_average',
          confidence: 'LOW',
          details: {
            fleetId: 'ks-fleet',
            fleetCode: 'KS',
            dayType: 'WEEKDAY',
          },
        };

        expect(result.source).toBe('fleet_average');
        expect(result.confidence).toBe('LOW');
        expect(result.details?.fleetId).toBeDefined();
      });

      test('should include minimal fields for system default', () => {
        const result: DailyRateResult = {
          dailyKm: 250,
          source: 'system_default',
          confidence: 'ESTIMATED',
        };

        expect(result.dailyKm).toBe(250);
        expect(result.confidence).toBe('ESTIMATED');
      });
    });

    describe('MileageProjection', () => {
      test('should include cumulative mileage tracking', () => {
        const projections: MileageProjection[] = [
          {
            date: '2026-01-19',
            projectedDailyKm: 300,
            cumulativeKm: 50300,
            source: 'route:nsl',
            confidence: 'MEDIUM',
          },
          {
            date: '2026-01-20',
            projectedDailyKm: 300,
            cumulativeKm: 50600,
            source: 'route:nsl',
            confidence: 'MEDIUM',
          },
          {
            date: '2026-01-21',
            projectedDailyKm: 300,
            cumulativeKm: 50900,
            source: 'route:nsl',
            confidence: 'MEDIUM',
          },
        ];

        // Verify cumulative tracking
        expect(projections[1].cumulativeKm - projections[0].cumulativeKm).toBe(
          projections[1].projectedDailyKm
        );
        expect(projections[2].cumulativeKm - projections[1].cumulativeKm).toBe(
          projections[2].projectedDailyKm
        );
      });
    });

    describe('RouteProfileWithMeta', () => {
      test('should include route code and name metadata', () => {
        const profile: RouteProfileWithMeta = {
          id: 'profile-123',
          routeId: 'route-456',
          effectiveDate: '2026-01-01',
          weekdayKm: 320,
          saturdayKm: 256,
          sundayKm: 224,
          holidayKm: 192,
          peakSeasonMultiplier: '1.15',
          offPeakMultiplier: '1.0',
          serviceHoursPerDay: '18.0',
          roundTripKm: '32.00',
          tripsPerDay: 10,
          source: 'MEASURED',
          confidence: 'HIGH',
          notes: 'Based on 2025 Q4 data',
          createdAt: new Date(),
          updatedAt: new Date(),
          routeCode: 'NSL',
          routeName: 'North-South Line',
        };

        expect(profile.routeCode).toBe('NSL');
        expect(profile.routeName).toBe('North-South Line');
      });
    });

    describe('CreateProfileRequest', () => {
      test('should have required fields', () => {
        const request: CreateProfileRequest = {
          routeId: 'route-123',
          weekdayKm: 320,
        };

        expect(request.routeId).toBeDefined();
        expect(request.weekdayKm).toBeDefined();
      });

      test('should support optional fields', () => {
        const request: CreateProfileRequest = {
          routeId: 'route-123',
          effectiveDate: '2026-01-01',
          weekdayKm: 320,
          saturdayKm: 256,
          sundayKm: 224,
          holidayKm: 192,
          peakSeasonMultiplier: 1.15,
          offPeakMultiplier: 1.0,
          serviceHoursPerDay: 18,
          roundTripKm: 32,
          tripsPerDay: 10,
          source: 'MEASURED',
          confidence: 'HIGH',
          notes: 'Initial profile',
        };

        expect(request.saturdayKm).toBe(256);
        expect(request.peakSeasonMultiplier).toBe(1.15);
      });
    });

    describe('UpdateProfileRequest', () => {
      test('should allow partial updates', () => {
        const request: UpdateProfileRequest = {
          weekdayKm: 350, // Only updating weekday km
        };

        expect(request.weekdayKm).toBe(350);
        expect(request.saturdayKm).toBeUndefined();
      });

      test('should allow nullifying optional fields', () => {
        const request: UpdateProfileRequest = {
          saturdayKm: null, // Explicitly remove Saturday km
          notes: null,
        };

        expect(request.saturdayKm).toBeNull();
        expect(request.notes).toBeNull();
      });
    });

    describe('ProfileListFilters', () => {
      test('should support filtering by route', () => {
        const filters: ProfileListFilters = {
          routeId: 'route-123',
        };
        expect(filters.routeId).toBeDefined();
      });

      test('should support filtering by multiple routes', () => {
        const filters: ProfileListFilters = {
          routeIds: ['route-1', 'route-2', 'route-3'],
        };
        expect(filters.routeIds?.length).toBe(3);
      });

      test('should support filtering by confidence', () => {
        const filters: ProfileListFilters = {
          confidence: 'HIGH',
        };
        expect(filters.confidence).toBe('HIGH');
      });

      test('should support filtering by multiple confidence levels', () => {
        const filters: ProfileListFilters = {
          confidence: ['HIGH', 'MEDIUM'],
        };
        expect(Array.isArray(filters.confidence)).toBe(true);
      });

      test('should support date range filtering', () => {
        const filters: ProfileListFilters = {
          effectiveDateFrom: '2026-01-01',
          effectiveDateTo: '2026-12-31',
        };
        expect(filters.effectiveDateFrom).toBeDefined();
        expect(filters.effectiveDateTo).toBeDefined();
      });
    });

    describe('FleetAverageResult', () => {
      test('should include calculation metadata', () => {
        const result: FleetAverageResult = {
          fleetId: 'ks-fleet',
          fleetCode: 'KS',
          averageDailyKm: 285,
          sampleSize: 150,
          periodStart: '2025-12-20',
          periodEnd: '2026-01-19',
          confidence: 'MEDIUM',
        };

        expect(result.sampleSize).toBe(150);
        expect(result.averageDailyKm).toBe(285);
        // Large sample size → MEDIUM confidence (fleet average is never HIGH)
        expect(result.confidence).toBe('MEDIUM');
      });

      test('should have lower confidence with small sample size', () => {
        const result: FleetAverageResult = {
          fleetId: 'ks-fleet',
          fleetCode: 'KS',
          averageDailyKm: 270,
          sampleSize: 5,
          periodStart: '2026-01-14',
          periodEnd: '2026-01-19',
          confidence: 'ESTIMATED',
        };

        // Small sample size → ESTIMATED confidence
        expect(result.confidence).toBe('ESTIMATED');
      });
    });
  });

  describe('Fallback Hierarchy Validation', () => {
    test('should document fallback order: route → fleet_average → system_default', () => {
      // This test documents the expected fallback behavior
      // 1. Route-specific profile (highest confidence)
      // 2. Fleet-wide average from mileage readings
      // 3. System default: 250 km/day (conservative)

      const sources: RateSource[] = [
        'route:nsl-uuid', // Priority 1
        'fleet_average', // Priority 2
        'system_default', // Priority 3 (fallback)
      ];

      expect(sources.length).toBe(3);
      expect(sources[0].startsWith('route:')).toBe(true);
      expect(sources[1]).toBe('fleet_average');
      expect(sources[2]).toBe('system_default');
    });

    test('system default should be 250 km/day', () => {
      // Conservative system default documented in spec
      const SYSTEM_DEFAULT_DAILY_KM = 250;
      expect(SYSTEM_DEFAULT_DAILY_KM).toBe(250);
    });
  });

  describe('Day Type Multipliers', () => {
    test('should apply correct default multipliers', () => {
      // Default multipliers relative to weekday baseline
      const multipliers = {
        WEEKDAY: 1.0,
        SATURDAY: 0.8,
        SUNDAY: 0.7,
        HOLIDAY: 0.6,
      };

      // Example: weekday km = 300
      const weekdayKm = 300;

      expect(Math.round(weekdayKm * multipliers.WEEKDAY)).toBe(300);
      expect(Math.round(weekdayKm * multipliers.SATURDAY)).toBe(240);
      expect(Math.round(weekdayKm * multipliers.SUNDAY)).toBe(210);
      expect(Math.round(weekdayKm * multipliers.HOLIDAY)).toBe(180);
    });
  });

  describe('Seasonal Multiplier Application', () => {
    test('should apply peak season multiplier correctly', () => {
      const baseKm = 300;
      const peakMultiplier = 1.15; // CNY period

      const adjustedKm = Math.round(baseKm * peakMultiplier);
      expect(adjustedKm).toBe(345);
    });

    test('should apply off-peak multiplier correctly', () => {
      const baseKm = 300;
      const offPeakMultiplier = 1.0; // Standard

      const adjustedKm = Math.round(baseKm * offPeakMultiplier);
      expect(adjustedKm).toBe(300);
    });

    test('should handle reduced off-peak multiplier', () => {
      const baseKm = 300;
      const offPeakMultiplier = 0.95; // Slightly reduced during very quiet periods

      const adjustedKm = Math.round(baseKm * offPeakMultiplier);
      expect(adjustedKm).toBe(285);
    });
  });

  describe('Mileage Projection Calculations', () => {
    test('should calculate cumulative mileage correctly', () => {
      const startingMileage = 50000;
      const dailyRates = [300, 300, 240, 210, 300, 300, 300]; // Week with Sat/Sun

      let cumulative = startingMileage;
      const projections: { day: number; daily: number; cumulative: number }[] = [];

      for (let i = 0; i < dailyRates.length; i++) {
        cumulative += dailyRates[i];
        projections.push({
          day: i + 1,
          daily: dailyRates[i],
          cumulative,
        });
      }

      // Total km for the week
      const totalWeekKm = dailyRates.reduce((sum, km) => sum + km, 0);
      expect(totalWeekKm).toBe(1950);

      // Final cumulative
      expect(projections[6].cumulative).toBe(51950);
    });

    test('should project date for target mileage', () => {
      const currentMileage = 45000;
      const targetMileage = 50000;
      const dailyKm = 300;

      const daysNeeded = Math.ceil((targetMileage - currentMileage) / dailyKm);
      expect(daysNeeded).toBe(17); // 5000 km / 300 km per day = 16.67 → 17 days
    });

    test('should handle already-reached target mileage', () => {
      const currentMileage = 55000;
      const targetMileage = 50000;

      // Target already reached
      expect(currentMileage >= targetMileage).toBe(true);
      // Should return 0 days needed
      const daysNeeded = currentMileage >= targetMileage ? 0 : 999;
      expect(daysNeeded).toBe(0);
    });
  });

  describe('Confidence Level Determination', () => {
    test('should assign HIGH confidence to route-specific profiles', () => {
      // Route profiles can have HIGH confidence
      const profileConfidence: ConfidenceLevel = 'HIGH';
      expect(profileConfidence).toBe('HIGH');
    });

    test('should cap fleet average at MEDIUM confidence', () => {
      // Fleet average is never HIGH - route-specific is preferred
      const sampleSize = 100;
      const minForMedium = 20;

      // Even with large sample, fleet average caps at MEDIUM
      const confidence: ConfidenceLevel =
        sampleSize >= minForMedium ? 'MEDIUM' : 'LOW';
      expect(confidence).toBe('MEDIUM');
    });

    test('should assign LOW confidence to small sample fleet average', () => {
      const sampleSize = 15;
      const minForMedium = 20;
      const minForLow = 10;

      const confidence: ConfidenceLevel =
        sampleSize >= minForMedium
          ? 'MEDIUM'
          : sampleSize >= minForLow
            ? 'LOW'
            : 'ESTIMATED';
      expect(confidence).toBe('LOW');
    });

    test('should assign ESTIMATED confidence to system default', () => {
      // System default always has ESTIMATED confidence
      const defaultConfidence: ConfidenceLevel = 'ESTIMATED';
      expect(defaultConfidence).toBe('ESTIMATED');
    });
  });

  describe('Validation Rules', () => {
    test('weekdayKm should be between 0 and 2000', () => {
      const validValues = [0, 100, 250, 500, 1000, 2000];
      const invalidValues = [-1, 2001, 5000];

      for (const km of validValues) {
        expect(km >= 0 && km <= 2000).toBe(true);
      }

      for (const km of invalidValues) {
        expect(km >= 0 && km <= 2000).toBe(false);
      }
    });

    test('horizonDays should be between 1 and 3650', () => {
      const validValues = [1, 7, 30, 365, 3650];
      const invalidValues = [0, -1, 3651, 10000];

      for (const days of validValues) {
        expect(days >= 1 && days <= 3650).toBe(true);
      }

      for (const days of invalidValues) {
        expect(days >= 1 && days <= 3650).toBe(false);
      }
    });
  });

  describe('Projection Error Estimation', () => {
    test('should estimate 12-year projection error from using wrong source', () => {
      // This documents the importance of route-specific profiles
      const years = 12;
      const daysPerYear = 365;
      const totalDays = years * daysPerYear;

      const routeSpecificKm = 320; // Actual route average
      const fleetAverageKm = 285; // Fleet-wide average
      const systemDefaultKm = 250; // Conservative default

      // Error from using fleet average instead of route-specific
      const fleetAverageError = Math.abs(routeSpecificKm - fleetAverageKm) * totalDays;
      expect(fleetAverageError).toBe(153300); // 35 km/day * 4380 days = 153,300 km error

      // Error from using system default instead of route-specific
      const systemDefaultError = Math.abs(routeSpecificKm - systemDefaultKm) * totalDays;
      expect(systemDefaultError).toBe(306600); // 70 km/day * 4380 days = 306,600 km error

      // This demonstrates why route-specific profiles are critical
      // 60,000+ km error mentioned in spec is conservative
    });
  });

  describe('Edge Cases', () => {
    test('should handle profile with no weekend km defined', () => {
      const weekdayKm = 300;
      const saturdayKm: number | undefined = undefined;

      // Should fall back to weekday * 0.8
      const effectiveSaturdayKm = saturdayKm ?? Math.round(weekdayKm * 0.8);
      expect(effectiveSaturdayKm).toBe(240);
    });

    test('should handle profile with all day types explicitly defined', () => {
      const profile = {
        weekdayKm: 300,
        saturdayKm: 280, // Custom, not using default multiplier
        sundayKm: 260,
        holidayKm: 150, // Very quiet holiday service
      };

      expect(profile.saturdayKm).toBe(280);
      expect(profile.sundayKm).toBe(260);
      expect(profile.holidayKm).toBe(150);
    });

    test('should handle zero km days', () => {
      // Some scenarios might have zero service
      const dailyKm = 0;
      const startMileage = 50000;

      const projectedMileage = startMileage + dailyKm;
      expect(projectedMileage).toBe(50000); // No change
    });

    test('should handle seasonal multiplier edge cases', () => {
      // Very high peak multiplier (e.g., CNY golden week)
      const baseKm = 300;
      const extremePeakMultiplier = 1.5;

      const peakKm = Math.round(baseKm * extremePeakMultiplier);
      expect(peakKm).toBe(450);
    });
  });

  describe('Integration Considerations', () => {
    test('calculateDailyRate is used by PM scheduling', () => {
      // Document that PM scheduler uses this to determine when trains hit thresholds
      // PM scheduling needs to know: when will train X reach Y km?
      const pmInterval = 30000; // C1 PM every 30,000 km
      const currentMileage = 28500;
      const remainingToNextPm = pmInterval - (currentMileage % pmInterval);

      expect(remainingToNextPm).toBe(1500); // 1,500 km until next C1
    });

    test('projectMileage is used by drift monitoring', () => {
      // Drift monitor compares projected vs. actual
      const projected = 52000;
      const actual = 51500;
      const driftKm = actual - projected;
      const driftPct = (driftKm / projected) * 100;

      expect(driftKm).toBe(-500); // Behind projection
      expect(driftPct).toBeCloseTo(-0.96, 1); // About -1%
    });

    test('projectDateForMileage is used for compliance windows', () => {
      // Determines when train will be in PM compliance window
      const currentMileage = 27000;
      const complianceWindowStart = 28500; // -5% from 30,000
      const dailyKm = 300;

      const daysToWindowStart = Math.ceil(
        (complianceWindowStart - currentMileage) / dailyKm
      );
      expect(daysToWindowStart).toBe(5); // 5 days until compliance window opens
    });
  });

  describe('Business Rules', () => {
    test('system default (250 km) is conservative to avoid over-scheduling', () => {
      // Under-projecting mileage means PM comes later than expected
      // This is safer than over-projecting (which could miss PM deadlines)
      const conservativeDefault = 250;
      const typicalRouteKm = 300;

      expect(conservativeDefault).toBeLessThan(typicalRouteKm);
    });

    test('fleet average uses 30-day rolling window', () => {
      const lookbackDays = 30;
      expect(lookbackDays).toBe(30);

      // This balances recency (recent changes in service) with stability
    });

    test('only VALID mileage readings are used for fleet average', () => {
      // Anomalous readings (NEGATIVE, SPIKE, DUPLICATE) are excluded
      const validStatuses = ['VALID'];
      const excludedStatuses = ['PENDING', 'ANOMALY', 'CORRECTED'];

      expect(validStatuses).not.toContain('ANOMALY');
      expect(excludedStatuses).toContain('ANOMALY');
    });
  });
});

