/**
 * MMS Ingestion Service Tests
 *
 * Tests for CSV file processing, validation, anomaly detection,
 * and meter event handling.
 *
 * Unit tests run without database. Integration tests require PostgreSQL.
 *
 * @see specs/004-domain-services.md Section 4.2
 */

import { describe, test, expect, beforeEach, afterEach, beforeAll } from 'bun:test';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { IngestionService } from './ingestion';
import { db } from '../lib/db/connection';
import { trains, mileageReadings, meterEvents, fleets, depots } from '../lib/db/schema';
import { eq, sql } from 'drizzle-orm';

// =============================================================================
// Test Setup
// =============================================================================

const TEST_INBOX_PATH = '/tmp/mms-test-inbox';
const TEST_PROCESSED_PATH = '/tmp/mms-test-processed';

let service: IngestionService;
let testDepotId: string;
let testFleetId: string;
let testTrainIds: string[] = [];
let databaseAvailable = false;

// Check if database is available
async function checkDatabaseConnection(): Promise<boolean> {
  try {
    await db.execute(sql`SELECT 1`);
    return true;
  } catch {
    return false;
  }
}

// Create test directories and clean up
function setupTestDirectories(): void {
  [TEST_INBOX_PATH, TEST_PROCESSED_PATH].forEach((dir) => {
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
  });
}

function cleanupTestDirectories(): void {
  [TEST_INBOX_PATH, TEST_PROCESSED_PATH].forEach((dir) => {
    if (fs.existsSync(dir)) {
      fs.readdirSync(dir).forEach((file) => {
        fs.unlinkSync(path.join(dir, file));
      });
    }
  });
}

// Create a test CSV file
function createTestCsv(
  filename: string,
  rows: Array<{ train_number: string; reading_date: string; odometer_km: number }>
): string {
  const header = 'train_number,reading_date,odometer_km';
  const lines = rows.map((r) => `${r.train_number},${r.reading_date},${r.odometer_km}`);
  const content = [header, ...lines].join('\n');

  const filePath = path.join(TEST_INBOX_PATH, filename);
  fs.writeFileSync(filePath, content);

  return filePath;
}

// Create test data in database
async function setupTestData(): Promise<void> {
  if (!databaseAvailable) return;

  // Create test depot
  const [depot] = await db.insert(depots).values({
    code: 'TEST-DEPOT',
    name: 'Test Depot',
    timezone: 'UTC',
  }).returning();
  testDepotId = depot.id;

  // Create test fleet
  const [fleet] = await db.insert(fleets).values({
    code: 'TEST-FLEET',
    name: 'Test Fleet',
    manufacturer: 'Test Manufacturer',
    carsPerTrain: 4,
    baseDepotId: testDepotId,
  }).returning();
  testFleetId = fleet.id;

  // Create test trains
  for (let i = 1; i <= 3; i++) {
    const [train] = await db.insert(trains).values({
      trainNumber: `T00${i}`,
      fleetId: testFleetId,
      currentMileageKm: 100000 + (i * 10000),
      fitnessStatus: 'FIT',
      currentDepotId: testDepotId,
      homeDepotId: testDepotId,
    }).returning();
    testTrainIds.push(train.id);
  }
}

// Clean up test data
async function cleanupTestData(): Promise<void> {
  if (!databaseAvailable) return;

  // Delete in reverse order of dependencies
  if (testTrainIds.length > 0) {
    await db.delete(mileageReadings).where(
      sql`${mileageReadings.trainId} = ANY(${testTrainIds}::uuid[])`
    );
    await db.delete(meterEvents).where(
      sql`${meterEvents.trainId} = ANY(${testTrainIds}::uuid[])`
    );
    await db.delete(trains).where(
      sql`${trains.id} = ANY(${testTrainIds}::uuid[])`
    );
  }

  if (testFleetId) {
    await db.delete(fleets).where(eq(fleets.id, testFleetId));
  }

  if (testDepotId) {
    await db.delete(depots).where(eq(depots.id, testDepotId));
  }

  testTrainIds = [];
}

