        const horizonEnd = new Date(today.getTime() + DEFAULT_HORIZON_WEEKS * 7 * 24 * 60 * 60 * 1000);

        const horizonDays = Math.ceil(
          (horizonEnd.getTime() - today.getTime()) / (1000 * 60 * 60 * 24)
