      test('overdue PMs should be prioritized', () => {
        const pms: Array<{ pmCode: string; isOverdue: boolean; dueDate: string }> = [
          { pmCode: 'C1-001', isOverdue: false, dueDate: '2026-02-15' },
          { pmCode: 'C2-001', isOverdue: true, dueDate: '2026-01-10' },
          { pmCode: 'C1-002', isOverdue: false, dueDate: '2026-02-01' },
          { pmCode: 'C3-001', isOverdue: true, dueDate: '2026-01-05' },
        ];

        // Sort by overdue first, then by due date
        const sorted = [...pms].sort((a, b) => {
          if (a.isOverdue && !b.isOverdue) return -1;
          if (!a.isOverdue && b.isOverdue) return 1;
          return a.dueDate.localeCompare(b.dueDate);
        });

        // Overdue PMs should be first
        expect(sorted[0].isOverdue).toBe(true);
        expect(sorted[1].isOverdue).toBe(true);
        expect(sorted[2].isOverdue).toBe(false);
        expect(sorted[3].isOverdue).toBe(false);

        // Among overdue, earlier due date first
        expect(sorted[0].pmCode).toBe('C3-001');
        expect(sorted[1].pmCode).toBe('C2-001');
