      // Explanation should be complete
      expect(explanation.mileageTrigger.intervalKm).toBeDefined();
      expect(explanation.timeTrigger.intervalMonths).toBeDefined();
      expect(explanation.trackSelection.candidateTracks).toBeGreaterThan(0);
      expect(explanation.materialCheck.totalParts).toBeGreaterThan(0);
      expect(explanation.constraints).toBeInstanceOf(Array);
    });

    test('explanation should record hierarchy satisfaction', () => {
      const explanation: SchedulingExplanation = {
        mileageTrigger: {
          intervalKm: 50000,
          currentMileageKm: 210000,
          lastPmMileageKm: null,
          kmSinceLastPm: null,
          kmUntilDue: 40000,
        },
        timeTrigger: {
          intervalMonths: 6,
          lastPmDate: null,
          daysSinceLastPm: null,
          daysUntilDue: null,
        },
        hierarchySatisfied: {
          satisfiedBy: 'C4',
          satisfiedOnDate: '2025-11-15',
          counterResetFrom: 200000,
        },
        trackSelection: {
          candidateTracks: 3,
          selectedTrackId: 'track-456',
          selectionReason: 'Track available with required capabilities',
        },
        materialCheck: {
          totalParts: 5,
          availableParts: 5,
          blockedParts: 0,
          warningParts: 0,
        },
        constraints: [],
      };

      // C4 satisfied this PM type on 2025-11-15, resetting counter from 200,000 km
      expect(explanation.hierarchySatisfied.satisfiedBy).toBe('C4');
      expect(explanation.hierarchySatisfied.satisfiedOnDate).toBe('2025-11-15');
      expect(explanation.hierarchySatisfied.counterResetFrom).toBe(200000);
    });

    test('explanation should record constraint violations', () => {
      const explanation: SchedulingExplanation = {
        mileageTrigger: {
          intervalKm: 50000,
          currentMileageKm: 248000,
          lastPmMileageKm: 200000,
          kmSinceLastPm: 48000,
          kmUntilDue: 2000,
        },
        timeTrigger: {
          intervalMonths: null,
          lastPmDate: null,
          daysSinceLastPm: null,
          daysUntilDue: null,
        },
        hierarchySatisfied: {
          satisfiedBy: null,
          satisfiedOnDate: null,
          counterResetFrom: null,
        },
        trackSelection: {
          candidateTracks: 0,
          selectedTrackId: null,
          selectionReason: 'No tracks available in the required date range',
        },
        materialCheck: {
          totalParts: 8,
          availableParts: 6,
          blockedParts: 2,
          warningParts: 0,
        },
        constraints: [
          'No suitable tracks available',
          'Blocked by material constraint: WHEEL-BEARING-001, MOTOR-BRUSH-001',
        ],
      };

      expect(explanation.constraints.length).toBe(2);
      expect(explanation.constraints[0]).toContain('tracks');
      expect(explanation.constraints[1]).toContain('material');
    });
  });
});

