/**
 * MMS Resilience Utilities
 *
 * Provides retry and circuit breaker patterns for handling transient failures.
 * Critical for integration with external systems (Maximo, OCC) and for
 * maintaining service availability during infrastructure issues.
 *
 * @see specs/007-integration.md - External system integration patterns
 * @see specs/004-domain-services.md - Service reliability requirements
 */

import { withSpan, addSpanEvent, SpanKind } from '../tracing';
import { TimeoutError, ExternalServiceError, ServiceUnavailableError } from '../errors';
import { logger } from '../logging/logger';

// =============================================================================
// Retry Configuration & Implementation
// =============================================================================

/**
 * Retry configuration options
 */
export interface RetryConfig {
  /** Maximum number of retry attempts */
  maxAttempts: number;
  /** Initial delay between retries (ms) */
  initialDelayMs: number;
  /** Maximum delay between retries (ms) */
  maxDelayMs: number;
  /** Backoff multiplier (e.g., 2 for exponential) */
  backoffMultiplier: number;
  /** Add random jitter to delays (prevents thundering herd) */
  jitter: boolean;
  /** Predicate to determine if an error is retryable */
  isRetryable?: (error: unknown) => boolean;
  /** Callback invoked before each retry */
  onRetry?: (error: unknown, attempt: number, delayMs: number) => void;
}

/**
 * Default retry configuration
 * Suitable for most transient failure scenarios
 */
export const DEFAULT_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 3,
  initialDelayMs: 1000,
  maxDelayMs: 30000,
  backoffMultiplier: 2,
  jitter: true,
  isRetryable: defaultIsRetryable,
};

/**
 * Aggressive retry configuration
 * Use for critical operations that must succeed
 */
export const AGGRESSIVE_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 5,
  initialDelayMs: 500,
  maxDelayMs: 60000,
  backoffMultiplier: 2,
  jitter: true,
  isRetryable: defaultIsRetryable,
};

/**
 * Quick retry configuration
 * Use for fast operations where quick recovery is expected
 */
export const QUICK_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 3,
  initialDelayMs: 100,
  maxDelayMs: 2000,
  backoffMultiplier: 2,
  jitter: true,
  isRetryable: defaultIsRetryable,
};

/**
 * External service retry configuration
 * Use for Maximo, OCC, and other external integrations
 */
export const EXTERNAL_SERVICE_RETRY_CONFIG: RetryConfig = {
  maxAttempts: 5,
  initialDelayMs: 2000,
  maxDelayMs: 60000,
  backoffMultiplier: 2,
  jitter: true,
  isRetryable: (error) => {
    // Retry on network errors, timeouts, and 5xx responses
    if (error instanceof TimeoutError) return true;
    if (error instanceof ExternalServiceError) return true;
    if (error instanceof ServiceUnavailableError) return true;

    // Check for fetch/network errors
    if (error instanceof Error) {
      const message = error.message.toLowerCase();
      return (
        message.includes('network') ||
        message.includes('timeout') ||
        message.includes('econnrefused') ||
        message.includes('econnreset') ||
        message.includes('socket hang up')
      );
    }

    return false;
  },
};

/**
 * Default function to determine if an error is retryable
 */
function defaultIsRetryable(error: unknown): boolean {
  // Don't retry validation errors or not found errors
  if (error instanceof Error) {
    const code = (error as Error & { code?: string }).code ?? '';
    const statusCode = (error as Error & { statusCode?: number }).statusCode ?? 0;

    // Don't retry 4xx client errors (except 408 timeout, 429 rate limit)
    if (statusCode >= 400 && statusCode < 500 && statusCode !== 408 && statusCode !== 429) {
      return false;
    }

    // Don't retry certain error codes
    if (code.startsWith('BUS_') || code.startsWith('AUTH_')) {
      return false;
    }
  }

  return true;
}

/**
 * Calculate delay for a given attempt with optional jitter
 */
function calculateDelay(attempt: number, config: RetryConfig): number {
  const exponentialDelay = config.initialDelayMs * Math.pow(config.backoffMultiplier, attempt - 1);
  let delay = Math.min(exponentialDelay, config.maxDelayMs);

  if (config.jitter) {
    // Add ±25% jitter
    const jitterRange = delay * 0.25;
    delay = delay - jitterRange + Math.random() * jitterRange * 2;
  }

  return Math.round(delay);
}

/**
 * Sleep for a specified duration
 */
function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

/**
 * Execute a function with retry logic
 *
 * Uses exponential backoff with optional jitter to handle transient failures.
 * Integrates with OpenTelemetry tracing for observability.
 *
 * @example
 * ```typescript
 * const result = await withRetry(
 *   async () => {
 *     return await fetchFromMaximo('/api/workorders');
 *   },
 *   {
 *     maxAttempts: 5,
 *     initialDelayMs: 1000,
 *     isRetryable: (error) => error instanceof NetworkError
 *   },
 *   'fetchWorkOrders'
 * );
 * ```
 */
export async function withRetry<T>(
  fn: () => Promise<T>,
  config?: Partial<RetryConfig>,
  operationName?: string
): Promise<T> {
  const opts = { ...DEFAULT_RETRY_CONFIG, ...config };
  const name = operationName ?? 'retry';

  return withSpan(
    `resilience.${name}`,
    async (span) => {
      span.setAttribute('retry.max_attempts', opts.maxAttempts);
      let lastError: unknown;

      for (let attempt = 1; attempt <= opts.maxAttempts; attempt++) {
        try {
          span.setAttribute('retry.current_attempt', attempt);
          addSpanEvent('retry.attempt', { attempt });

          const result = await fn();

          if (attempt > 1) {
            addSpanEvent('retry.success', { attempt, totalAttempts: attempt });
          }

          return result;
        } catch (error) {
          lastError = error;

          // Check if we should retry
          const shouldRetry = attempt < opts.maxAttempts && (opts.isRetryable?.(error) ?? true);

          if (!shouldRetry) {
            addSpanEvent('retry.exhausted', {
              attempt,
              error: error instanceof Error ? error.message : String(error),
              retryable: opts.isRetryable?.(error) ?? true,
            });
            throw error;
          }

          // Calculate delay
          const delayMs = calculateDelay(attempt, opts);

          addSpanEvent('retry.waiting', {
            attempt,
            delayMs,
            error: error instanceof Error ? error.message : String(error),
          });

          // Invoke callback if provided
          opts.onRetry?.(error, attempt, delayMs);

          logger.warn(
            {
              operation: name,
              attempt,
              nextAttempt: attempt + 1,
              delayMs,
              error: error instanceof Error ? error.message : String(error),
            },
            `Retry attempt ${attempt}/${opts.maxAttempts} failed, waiting ${delayMs}ms`
          );

          await sleep(delayMs);
        }
      }

      // Should never reach here, but TypeScript needs this
      throw lastError;
    },
    { kind: SpanKind.INTERNAL }
  );
}

// =============================================================================
// Circuit Breaker Implementation
// =============================================================================

/**
 * Circuit breaker states
 */
export type CircuitState = 'CLOSED' | 'OPEN' | 'HALF_OPEN';

/**
 * Circuit breaker configuration
 */
export interface CircuitBreakerConfig {
  /** Number of failures before opening the circuit */
  failureThreshold: number;
  /** Number of successes in half-open state to close circuit */
  successThreshold: number;
  /** Time to wait before transitioning from OPEN to HALF_OPEN (ms) */
  resetTimeoutMs: number;
  /** Function to determine if an error counts as a failure */
  isFailure?: (error: unknown) => boolean;
  /** Callback when circuit state changes */
  onStateChange?: (from: CircuitState, to: CircuitState) => void;
}

/**
 * Default circuit breaker configuration
 */
export const DEFAULT_CIRCUIT_BREAKER_CONFIG: CircuitBreakerConfig = {
  failureThreshold: 5,
  successThreshold: 3,
  resetTimeoutMs: 30000,
  isFailure: () => true,
};

/**
 * Circuit breaker metrics
 */
export interface CircuitBreakerMetrics {
  state: CircuitState;
  failures: number;
  successes: number;
  lastFailureTime: Date | null;
  lastSuccessTime: Date | null;
  totalRequests: number;
  totalFailures: number;
  totalSuccesses: number;
}

/**
 * Circuit Breaker implementation
 *
 * Prevents cascading failures by stopping requests to a failing service.
 * Implements the standard circuit breaker pattern:
 * - CLOSED: Normal operation, requests flow through
 * - OPEN: Failures exceeded threshold, requests fail fast
 * - HALF_OPEN: Testing if service has recovered
 *
 * @example
 * ```typescript
 * const maximoBreaker = new CircuitBreaker({
 *   failureThreshold: 5,
 *   resetTimeoutMs: 30000,
 *   onStateChange: (from, to) => {
 *     logger.warn({ from, to }, 'Maximo circuit breaker state changed');
 *   }
 * }, 'maximo');
 *
 * // In service
 * const result = await maximoBreaker.execute(
 *   async () => fetchFromMaximo('/api/workorders')
 * );
 * ```
 */
export class CircuitBreaker {
  private state: CircuitState = 'CLOSED';
  private failures = 0;
  private successes = 0;
  private lastFailureTime: Date | null = null;
  private lastSuccessTime: Date | null = null;
  private totalRequests = 0;
  private totalFailures = 0;
  private totalSuccesses = 0;
  private readonly config: CircuitBreakerConfig;
  private readonly name: string;
  private readonly log: typeof logger;

  constructor(config: Partial<CircuitBreakerConfig> = {}, name = 'default') {
    this.config = { ...DEFAULT_CIRCUIT_BREAKER_CONFIG, ...config };
    this.name = name;
    this.log = logger.child({ circuitBreaker: name });
  }

  /**
   * Execute a function through the circuit breaker
   */
  async execute<T>(fn: () => Promise<T>): Promise<T> {
    return withSpan(
      `circuitBreaker.${this.name}`,
      async (span) => {
        span.setAttribute('circuit_breaker.name', this.name);
        span.setAttribute('circuit_breaker.state', this.state);

        this.totalRequests++;

        // Check if circuit should transition from OPEN to HALF_OPEN
        this.checkResetTimeout();

        // If circuit is OPEN, fail fast
        if (this.state === 'OPEN') {
          addSpanEvent('circuit_breaker.rejected', { state: this.state });
          throw new ServiceUnavailableError(
            `Circuit breaker ${this.name} is OPEN. Service unavailable.`,
            { retryAfter: Math.ceil(this.config.resetTimeoutMs / 1000) }
          );
        }

        try {
          const result = await fn();
          this.recordSuccess();
          addSpanEvent('circuit_breaker.success', { state: this.state });
          return result;
        } catch (error) {
          if (this.config.isFailure?.(error) ?? true) {
            this.recordFailure();
            addSpanEvent('circuit_breaker.failure', {
              state: this.state,
              failures: this.failures,
            });
          }
          throw error;
        }
      },
      { kind: SpanKind.INTERNAL }
    );
  }

  /**
   * Check if the reset timeout has elapsed and transition to HALF_OPEN
   */
  private checkResetTimeout(): void {
    if (this.state !== 'OPEN' || !this.lastFailureTime) return;

    const elapsed = Date.now() - this.lastFailureTime.getTime();
    if (elapsed >= this.config.resetTimeoutMs) {
      this.transition('HALF_OPEN');
    }
  }

  /**
   * Record a successful execution
   */
  private recordSuccess(): void {
    this.successes++;
    this.totalSuccesses++;
    this.lastSuccessTime = new Date();

    if (this.state === 'HALF_OPEN') {
      if (this.successes >= this.config.successThreshold) {
        this.transition('CLOSED');
      }
    } else if (this.state === 'CLOSED') {
      // Reset failure count on success in CLOSED state
      this.failures = 0;
    }
  }

  /**
   * Record a failed execution
   */
  private recordFailure(): void {
    this.failures++;
    this.totalFailures++;
    this.lastFailureTime = new Date();
    this.successes = 0; // Reset success count on failure

    if (this.state === 'HALF_OPEN') {
      // Any failure in HALF_OPEN opens the circuit again
      this.transition('OPEN');
    } else if (this.state === 'CLOSED') {
      if (this.failures >= this.config.failureThreshold) {
        this.transition('OPEN');
      }
    }
  }

  /**
   * Transition to a new state
   */
  private transition(to: CircuitState): void {
    const from = this.state;
    if (from === to) return;

    this.log.info({ from, to }, `Circuit breaker transitioning: ${from} -> ${to}`);

    this.state = to;
    this.failures = 0;
    this.successes = 0;

    this.config.onStateChange?.(from, to);
  }

  /**
   * Get current circuit breaker metrics
   */
  getMetrics(): CircuitBreakerMetrics {
    return {
      state: this.state,
      failures: this.failures,
      successes: this.successes,
      lastFailureTime: this.lastFailureTime,
      lastSuccessTime: this.lastSuccessTime,
      totalRequests: this.totalRequests,
      totalFailures: this.totalFailures,
      totalSuccesses: this.totalSuccesses,
    };
  }

  /**
   * Get current state
   */
  getState(): CircuitState {
    this.checkResetTimeout();
    return this.state;
  }

  /**
   * Manually reset the circuit breaker to CLOSED state
   * Use with caution - primarily for testing or manual intervention
   */
  reset(): void {
    this.log.warn('Circuit breaker manually reset');
    this.state = 'CLOSED';
    this.failures = 0;
    this.successes = 0;
  }

  /**
   * Manually open the circuit
   * Use for graceful degradation scenarios
   */
  open(): void {
    this.log.warn('Circuit breaker manually opened');
    this.transition('OPEN');
    this.lastFailureTime = new Date();
  }
}

// =============================================================================
// Combined Retry + Circuit Breaker
// =============================================================================

/**
 * Execute a function with both retry logic and circuit breaker protection
 *
 * The circuit breaker wraps the retry logic, so if the circuit is open,
 * no retries will be attempted.
 *
 * @example
 * ```typescript
 * const result = await withResilience(
 *   async () => fetchFromMaximo('/api/workorders'),
 *   maximoCircuitBreaker,
 *   EXTERNAL_SERVICE_RETRY_CONFIG,
 *   'fetchWorkOrders'
 * );
 * ```
 */
export async function withResilience<T>(
  fn: () => Promise<T>,
  circuitBreaker: CircuitBreaker,
  retryConfig?: Partial<RetryConfig>,
  operationName?: string
): Promise<T> {
  return circuitBreaker.execute(async () => withRetry(fn, retryConfig, operationName));
}

// =============================================================================
// Timeout Utility
// =============================================================================

/**
 * Execute a function with a timeout
 *
 * @example
 * ```typescript
 * const result = await withTimeout(
 *   async () => slowOperation(),
 *   5000,
 *   'slowOperation'
 * );
 * ```
 */
export async function withTimeout<T>(
  fn: () => Promise<T>,
  timeoutMs: number,
  operationName?: string
): Promise<T> {
  const name = operationName ?? 'operation';

  return new Promise((resolve, reject) => {
    const timer = setTimeout(() => {
      reject(
        new TimeoutError(`Operation ${name} timed out after ${timeoutMs}ms`, {
          operation: name,
          timeoutMs,
        })
      );
    }, timeoutMs);

    fn()
      .then((result) => {
        clearTimeout(timer);
        resolve(result);
      })
      .catch((error) => {
        clearTimeout(timer);
        reject(error);
      });
  });
}

